import{_ as e,o as a,c as r,ag as d}from"./chunks/framework.DmWB24NN.js";const u=JSON.parse('{"title":"CHAPTER 10: ADVENTURING & EXPLORATION","description":"","frontmatter":{},"headers":[],"relativePath":"Book I - Core Rules/B01 - Chapter 10_ Adventuring & Exploration.md","filePath":"Book I - Core Rules/B01 - Chapter 10_ Adventuring & Exploration.md"}'),n={name:"Book I - Core Rules/B01 - Chapter 10_ Adventuring & Exploration.md"};function o(i,t,s,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="chapter-10-adventuring-exploration" tabindex="-1"><strong>CHAPTER 10: ADVENTURING &amp; EXPLORATION</strong> <a class="header-anchor" href="#chapter-10-adventuring-exploration" aria-label="Permalink to &quot;**CHAPTER 10: ADVENTURING &amp; EXPLORATION**&quot;">​</a></h1><h2 id="time" tabindex="-1"><strong>Time</strong> <a class="header-anchor" href="#time" aria-label="Permalink to &quot;**Time**&quot;">​</a></h2><p>The passage of time in play is the GM&#39;s domain. In most campaigns, it functions as it does in the real world. Precise time in the game uses two units:</p><p>A <strong>round</strong> is approximately one minute of activity. A <strong>turn</strong> is ten rounds, or ten minutes. Long-term time — days, weeks, months — can be compressed when nothing significant occurs. Three weeks of travel can pass in a sentence if nothing happens during them worth playing out.</p><hr><h2 id="movement" tabindex="-1"><strong>Movement</strong> <a class="header-anchor" href="#movement" aria-label="Permalink to &quot;**Movement**&quot;">​</a></h2><p>Each character has a base Movement Value (MV) listed by ancestry. This represents how far they move in a single round. Four movement modes apply depending on the circumstances.</p><p><strong>Walking.</strong> Standard pace across open terrain — city streets, wilderness, clear roads. Characters move a number of meters equal to their MV × 10 per round.</p><p><strong>Cautious Walk.</strong> Used in confined or hostile environments — underground, in dungeons, inside buildings, whenever traps or ambushes are possible. Characters move a number of meters equal to their MV × 3 per round. The slower pace allows them to spot traps, secret doors, and environmental hazards.</p><p><strong>Hustle.</strong> Moving at walking speed in a situation that would normally require a cautious walk. Characters use their full walking MV in meters (MV × 10) but suffer −1 to their own surprise rolls and grant opponents +1 to theirs. Hustling characters cannot spot traps, secret doors, or other features requiring careful observation.</p><p><strong>Run.</strong> Used when fleeing pursuit. Initiative is rolled for both the fleeing party and the pursuers. If the fleeing party wins, the gap between them increases by three meters per point of initiative difference in confined terrain, or ten meters per point in open terrain. If the pursuers win, it closes by the same amount. Runners suffer the same penalties as hustlers and cannot spot hidden features.</p><hr><h2 id="overland-movement" tabindex="-1"><strong>Overland Movement</strong> <a class="header-anchor" href="#overland-movement" aria-label="Permalink to &quot;**Overland Movement**&quot;">​</a></h2><p>A normal day&#39;s march lasts 10 hours. Under standard conditions, a character covers three times their MV in kilometers over that time. The slowest member of the group sets the pace.</p><p><strong>Forced march.</strong> Characters may push to cover four times their MV in kilometers per day. At the end of a forced march, all characters make a Constitution check (or a Fortitude save for creatures without a known Constitution). A −1 penalty applies for each consecutive day of forced marching. Failure means the party cannot force-march again without half a day of rest per day spent marching hard. Each half-day of rest also removes one point from the cumulative −1 attack roll penalty that forced marching imposes. Normal movement remains available even after a failed check.</p><p><strong>Mounted travel.</strong> A mounted rider covers 1.5 times their mount&#39;s MV in kilometers per day&#39;s march. Mounts can be pushed to three times their MV in kilometers per day, but must succeed on a Fortitude save with a cumulative −1 per consecutive pushed day — failure means the mount is limited to normal MV until rested for a full day. Pushing to four-and-a-half times their MV in kilometers requires a Fortitude save at −3; failure kills the mount from exhaustion. A mount that fails either save does not collapse immediately — the GM determines when and where it gives out.</p><hr><h2 id="terrain-and-roads" tabindex="-1"><strong>Terrain and Roads</strong> <a class="header-anchor" href="#terrain-and-roads" aria-label="Permalink to &quot;**Terrain and Roads**&quot;">​</a></h2><p>Terrain imposes a cost per kilometer traveled, deducted from the day&#39;s available travel points. A character with MV 12 has 36 travel points per day&#39;s march, each representing one kilometer of progress.</p><h3 id="table-10-1-terrain-costs" tabindex="-1"><strong>Table 10.1: Terrain Costs</strong> <a class="header-anchor" href="#table-10-1-terrain-costs" aria-label="Permalink to &quot;**Table 10.1: Terrain Costs**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Terrain</th><th>Cost per Kilometer</th></tr></thead><tbody><tr><td>Clear, farmland, grassland</td><td>1</td></tr><tr><td>Barren, wasteland, scrub</td><td>2</td></tr><tr><td>Desert, rocky</td><td>2</td></tr><tr><td>Hills, rolling</td><td>2</td></tr><tr><td>Forest, light</td><td>2</td></tr><tr><td>Glacier</td><td>2</td></tr><tr><td>Desert, sand</td><td>3</td></tr><tr><td>Forest, medium</td><td>3</td></tr><tr><td>Tundra</td><td>3</td></tr><tr><td>Forest, heavy</td><td>4</td></tr><tr><td>Hills, steep</td><td>4</td></tr><tr><td>Mountains, low</td><td>4</td></tr><tr><td>Moor</td><td>4</td></tr><tr><td>Mountains, medium</td><td>6</td></tr><tr><td>Jungle, medium</td><td>6</td></tr><tr><td>Mountains, high</td><td>8</td></tr><tr><td>Jungle, heavy</td><td>8</td></tr><tr><td>Marsh, swamp</td><td>8</td></tr></tbody></table><p><strong>Trails</strong> reduce terrain cost by half (4 becomes 2, 2 becomes 1). Clear plains and farmland cannot be improved by a trail.</p><p><strong>Roads</strong> are rare — built near cities and major trade routes. Level ground with a road costs half a point per kilometer. Roads in mountainous terrain function as trails.</p><p>Wheeled vehicles cannot travel in terrain with a cost above 1 without a road or trail. Dog sleds are restricted to snow and ice, but travel with no movement penalty on them.</p><h3 id="table-10-2-obstacles-and-hindrances" tabindex="-1"><strong>Table 10.2: Obstacles and Hindrances</strong> <a class="header-anchor" href="#table-10-2-obstacles-and-hindrances" aria-label="Permalink to &quot;**Table 10.2: Obstacles and Hindrances**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Condition</th><th>Modifier (added to terrain cost)</th></tr></thead><tbody><tr><td>Chasm or cliff</td><td>+3</td></tr><tr><td>Ravine or ridge</td><td>+1</td></tr><tr><td>River (no bridge)</td><td>+1</td></tr><tr><td>Stream</td><td>+1</td></tr><tr><td>Rain, light</td><td>+1</td></tr><tr><td>Heavy wind</td><td>+2</td></tr><tr><td>Heavy fog</td><td>+1</td></tr><tr><td>Freezing temperatures</td><td>+1</td></tr><tr><td>Scorching temperatures</td><td>+1</td></tr><tr><td>Rain, heavy</td><td>×2</td></tr><tr><td>Snow, normal</td><td>×2</td></tr><tr><td>Mud</td><td>×2</td></tr><tr><td>Rain, torrential</td><td>×3</td></tr><tr><td>Ice storm</td><td>×2</td></tr><tr><td>Dust or sandstorm</td><td>×3</td></tr><tr><td>Blizzard</td><td>×4</td></tr></tbody></table><hr><h2 id="water-travel" tabindex="-1"><strong>Water Travel</strong> <a class="header-anchor" href="#water-travel" aria-label="Permalink to &quot;**Water Travel**&quot;">​</a></h2><h3 id="river" tabindex="-1"><strong>River</strong> <a class="header-anchor" href="#river" aria-label="Permalink to &quot;**River**&quot;">​</a></h3><p>Boat speed on rivers is modified by the current. Downstream: add current speed to boat speed. Upstream: subtract current speed.</p><p>Obstacles can be avoided by going upstream. Going downstream requires a good map or guide — without one, the pilot makes a Wisdom check to prevent capsizing at any hazard. A capsized boat is swept downstream and destroyed by waterfalls or severe rapids.</p><h3 id="table-10-3-boat-movement" tabindex="-1"><strong>Table 10.3: Boat Movement</strong> <a class="header-anchor" href="#table-10-3-boat-movement" aria-label="Permalink to &quot;**Table 10.3: Boat Movement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Vessel</th><th>m/Round</th><th>km/h</th><th>Cargo</th><th>Length</th></tr></thead><tbody><tr><td>Kayak</td><td>60 m</td><td>3</td><td>125 kg</td><td>2.5–3 m</td></tr><tr><td>Canoe, small</td><td>60 m</td><td>3</td><td>275 kg</td><td>3–4.5 m</td></tr><tr><td>Canoe, war</td><td>55 m</td><td>3</td><td>400 kg</td><td>7.5–10.5 m</td></tr><tr><td>Rowboat</td><td>50 m</td><td>2.5*</td><td>300 kg</td><td>2.5–3.5 m</td></tr><tr><td>Curragh</td><td>20 m</td><td>1.5*</td><td>300 kg</td><td>2.5–3 m</td></tr><tr><td>Keelboat/raft</td><td>20 m</td><td>1.5*</td><td>1,000 kg</td><td>4.5–6 m</td></tr><tr><td>Barge</td><td>20 m</td><td>1.5*</td><td>2,000 kg</td><td>7.5–12 m</td></tr></tbody></table><p>* <em>These vessels triple their movement when sails are raised, and the wind is favorable.</em></p><h3 id="ocean-travel" tabindex="-1"><strong>Ocean Travel</strong> <a class="header-anchor" href="#ocean-travel" aria-label="Permalink to &quot;**Ocean Travel**&quot;">​</a></h3><p>Ships are rated by km/h and seaworthiness. Speeds listed as two numbers separated by a slash give sail speed and rowing speed. Per round, a ship moves a number of meters equal to its km/h × 10.</p><p><strong>Emergency move</strong> is the top sustainable speed for a short period before causing damage to the ship and crew.</p><p><strong>Seaworthiness</strong> is the percentage chance of surviving a dangerous situation — storm, ramming, hidden obstacles, extended rough voyage. Roll percentile dice: a result above the seaworthiness rating means the ship sinks. Anchored vessels add +50% to their seaworthiness rating.</p><h3 id="table-10-4-ship-movement" tabindex="-1"><strong>Table 10.4: Ship Movement</strong> <a class="header-anchor" href="#table-10-4-ship-movement" aria-label="Permalink to &quot;**Table 10.4: Ship Movement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Ship</th><th>km/h</th><th>Emergency Move</th><th>Seaworthiness</th></tr></thead><tbody><tr><td>Caravel</td><td>6</td><td>8</td><td>70%</td></tr><tr><td>Coaster</td><td>5</td><td>6</td><td>50%</td></tr><tr><td>Cog</td><td>5</td><td>6</td><td>65%</td></tr><tr><td>Curragh</td><td>3/5</td><td>16</td><td>55%</td></tr><tr><td>Drakkar</td><td>3/6</td><td>19</td><td>50%</td></tr><tr><td>Dromond</td><td>3/14</td><td>19</td><td>40%</td></tr><tr><td>Galleon</td><td>5</td><td>10</td><td>75%</td></tr><tr><td>Great galley</td><td>5/10</td><td>18</td><td>45%</td></tr><tr><td>Knarr</td><td>6/3</td><td>19</td><td>65%</td></tr><tr><td>Longship</td><td>8/3</td><td>21</td><td>60%</td></tr></tbody></table><h3 id="table-10-5-weather-effects-on-ship-movement" tabindex="-1"><strong>Table 10.5: Weather Effects on Ship Movement</strong> <a class="header-anchor" href="#table-10-5-weather-effects-on-ship-movement" aria-label="Permalink to &quot;**Table 10.5: Weather Effects on Ship Movement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Weather</th><th>Sailing Modifier</th><th>Rowing Modifier</th></tr></thead><tbody><tr><td>Calm/windless</td><td>Cannot sail*</td><td>×1</td></tr><tr><td>Adverse wind</td><td>×½</td><td>×1</td></tr><tr><td>Light breeze</td><td>×1.5</td><td>×1</td></tr><tr><td>Moderate wind</td><td>×2</td><td>×1</td></tr><tr><td>Strong wind</td><td>×3</td><td>×1</td></tr><tr><td>Storm</td><td>×⅓**</td><td>×½**</td></tr><tr><td>Gale</td><td>×¼**</td><td>Cannot row</td></tr><tr><td>Hurricane</td><td>Cannot sail</td><td>Cannot row***</td></tr></tbody></table><p>* Ships using oars can still move normally in calm weather.<br> ** Seaworthiness check required.<br> *** Seaworthiness check at −45% penalty required.</p><p>Adverse winds and storms blow a ship off course by half its movement (or more). Strong wind also imposes −2 to all ranged attacks. Storms prevent normal missile fire. Gale-force winds prevent all missile fire, can uproot small trees, collapse weak structures, and endanger ships. Hurricane-force winds destroy sturdier buildings and tear ships apart.</p><h3 id="table-10-6-random-wind-by-season" tabindex="-1"><strong>Table 10.6: Random Wind by Season</strong> <a class="header-anchor" href="#table-10-6-random-wind-by-season" aria-label="Permalink to &quot;**Table 10.6: Random Wind by Season**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>2d6</th><th>Spring/Fall</th><th>Summer</th><th>Winter</th></tr></thead><tbody><tr><td>2</td><td>Calm</td><td>Calm</td><td>Calm</td></tr><tr><td>3</td><td>Calm</td><td>Calm</td><td>Light breeze</td></tr><tr><td>4</td><td>Light breeze</td><td>Calm</td><td>Light breeze</td></tr><tr><td>5</td><td>Moderate</td><td>Light breeze</td><td>Moderate</td></tr><tr><td>6</td><td>Moderate</td><td>Light breeze</td><td>Strong</td></tr><tr><td>7</td><td>Strong</td><td>Moderate</td><td>Strong</td></tr><tr><td>8</td><td>Storm</td><td>Moderate</td><td>Storm</td></tr><tr><td>9</td><td>Storm</td><td>Strong</td><td>Storm</td></tr><tr><td>10</td><td>Gale</td><td>Storm</td><td>Gale</td></tr><tr><td>11</td><td>Gale</td><td>Gale</td><td>Gale</td></tr><tr><td>12</td><td>Hurricane*</td><td>Hurricane*</td><td>Hurricane*</td></tr></tbody></table><p>* <em>Hurricanes only occur if the previous day&#39;s weather was already Gale. Otherwise treat as Gale.</em></p><hr><h2 id="aerial-movement" tabindex="-1"><strong>Aerial Movement</strong> <a class="header-anchor" href="#aerial-movement" aria-label="Permalink to &quot;**Aerial Movement**&quot;">​</a></h2><p>Aerial travel uses normal movement rules. Weather modifies it as terrain modifies overland travel — clear skies with no more than moderate wind are treated as open terrain.</p><p><strong>Tiny flyers</strong> (eagle-sized or smaller) are driven from the sky by strong winds. <strong>Man-sized flyers</strong> are forced down by gale-force winds. <strong>Large flyers</strong> cannot fly in storms. Nothing flies in a hurricane without magical protection.</p><h3 id="table-10-7-aerial-movement-modifiers" tabindex="-1"><strong>Table 10.7: Aerial Movement Modifiers</strong> <a class="header-anchor" href="#table-10-7-aerial-movement-modifiers" aria-label="Permalink to &quot;**Table 10.7: Aerial Movement Modifiers**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Condition</th><th>Modifier</th></tr></thead><tbody><tr><td>Strong wind</td><td>×½</td></tr><tr><td>Rain or snow</td><td>×½</td></tr><tr><td>Storm</td><td>×⅓</td></tr><tr><td>Gale</td><td>×¼</td></tr><tr><td>Hurricane</td><td>Impossible</td></tr></tbody></table><p>Modifiers are cumulative: gale force winds with rain apply ×¼ × ½ = ×⅛.</p><h3 id="aerial-combat" tabindex="-1"><strong>Aerial Combat</strong> <a class="header-anchor" href="#aerial-combat" aria-label="Permalink to &quot;**Aerial Combat**&quot;">​</a></h3><p>Aerial combat is fought in three dimensions. Most flyers must maintain forward momentum — they cannot stop in place. Rounds may pass where combatants circle without engaging, rolling initiative each round while maneuvering for position.</p><p><strong>Maneuver Class.</strong> Creatures and vehicles that fly have a Maneuver Class (MC) from 1 (Perfect) to 5 (Clumsy), indicating how tight a turn they can make.</p><p><strong>Speed Class.</strong> Five speed classes based on flying MV.</p><h3 id="table-10-8-speed-classes" tabindex="-1"><strong>Table 10.8: Speed Classes</strong> <a class="header-anchor" href="#table-10-8-speed-classes" aria-label="Permalink to &quot;**Table 10.8: Speed Classes**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Class</th><th>Movement Value</th></tr></thead><tbody><tr><td>Slow</td><td>12 or less</td></tr><tr><td>Average</td><td>13–24</td></tr><tr><td>Quick</td><td>25–36</td></tr><tr><td>Fast</td><td>37–48</td></tr><tr><td>God-like</td><td>49+</td></tr></tbody></table><h3 id="table-10-9-maneuver-classes" tabindex="-1"><strong>Table 10.9: Maneuver Classes</strong> <a class="header-anchor" href="#table-10-9-maneuver-classes" aria-label="Permalink to &quot;**Table 10.9: Maneuver Classes**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Class</th><th>Turns/Round</th><th>Passes</th><th>Hover</th><th>Min. Momentum</th></tr></thead><tbody><tr><td>Perfect</td><td>12</td><td>No limit</td><td>Yes</td><td>None</td></tr><tr><td>Good</td><td>6</td><td>1/round</td><td>Yes</td><td>None</td></tr><tr><td>Average</td><td>3</td><td>1 per 2 rounds</td><td>No</td><td>½ MV</td></tr><tr><td>Poor</td><td>2</td><td>1 per 3 rounds</td><td>No</td><td>½ MV</td></tr><tr><td>Clumsy</td><td>1</td><td>1 per 6 rounds</td><td>No</td><td>½ MV</td></tr></tbody></table><p><strong>Initiative in aerial combat.</strong> The more agile combatant gains a bonus to initiative equal to the difference in their Maneuver Classes (0–4). The faster combatant gains +1 per 2 points of Speed Class difference, maximum +2. Both bonuses may go to the same combatant.</p><p><strong>Passes</strong> represent the number of rounds between attack opportunities against a relatively stationary target. Add or subtract the Speed Class difference from a flyer&#39;s base number of rounds per attack. Only Perfect flyers may attack at their normal rate every round, regardless of positioning.</p><p><strong>Altitude and diving.</strong> A flyer above their opponent can dive to gain a charge bonus. Natural talons, claws, lances, and spears deal double damage on a successful dive attack. Attacks against a flyer directly above suffer −2.</p><p><strong>Damage and crashing.</strong> A flyer (except Perfect class) reduced to 50% HP or below drops to half MV and must land. If no safe landing is available, the GM adjudicates the crash — minimum 2d6 damage, maximum 10d6, based on altitude, speed, terrain, and size. A flyer striking a solid object in mid-air crashes, taking 2d6 per current Speed Class (max 10d6). A stalled flyer falls a distance equal to 5 × its momentum requirement before regaining flight if still above 50% HP.</p><hr><h2 id="getting-lost" tabindex="-1"><strong>Getting Lost</strong> <a class="header-anchor" href="#getting-lost" aria-label="Permalink to &quot;**Getting Lost**&quot;">​</a></h2><h3 id="lost" tabindex="-1"><strong>Lost</strong> <a class="header-anchor" href="#lost" aria-label="Permalink to &quot;**Lost**&quot;">​</a></h3><p>A party that doesn&#39;t know the route to their destination but knows how to return to their starting point is simply lost. Finding the right direction is a matter of time. This occurs when following unfamiliar or poorly marked trails or consulting inadequate maps. Annoying; rarely dangerous.</p><h3 id="hopelessly-lost" tabindex="-1"><strong>Hopelessly Lost</strong> <a class="header-anchor" href="#hopelessly-lost" aria-label="Permalink to &quot;**Hopelessly Lost**&quot;">​</a></h3><p>A party that doesn&#39;t know where they are, which direction to travel, or how to return is hopelessly lost. Check each day characters travel overland without following a road, river, or well-traveled trail — and whenever a followed river empties into a swamp, estuary, or delta.</p><p>If the percentile roll falls below the modified chance, the party is hopelessly lost. The GM rolls 1d8 to determine the general direction of travel each day while lost (1 = north, 2 = northeast, 3 = east, 4 = southeast, 5 = south, 6 = southwest, 7 = west, 8 = northwest), and does not inform players that they are lost until circumstances make it obvious.</p><h3 id="table-10-10-chance-of-becoming-hopelessly-lost" tabindex="-1"><strong>Table 10.10: Chance of Becoming Hopelessly Lost</strong> <a class="header-anchor" href="#table-10-10-chance-of-becoming-hopelessly-lost" aria-label="Permalink to &quot;**Table 10.10: Chance of Becoming Hopelessly Lost**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Terrain</th><th>Base Chance</th></tr></thead><tbody><tr><td>Level, open ground</td><td>10%</td></tr><tr><td>Rolling ground</td><td>20%</td></tr><tr><td>Open sea</td><td>20%</td></tr><tr><td>Lightly wooded</td><td>30%</td></tr><tr><td>Mountainous</td><td>50%</td></tr><tr><td>Rough, wooded, hilly</td><td>40%</td></tr><tr><td>Swamp</td><td>60%</td></tr><tr><td>Thick forest</td><td>70%</td></tr><tr><td>Jungle</td><td>80%</td></tr></tbody></table><h3 id="table-10-11-lost-chance-modifiers" tabindex="-1"><strong>Table 10.11: Lost Chance Modifiers</strong> <a class="header-anchor" href="#table-10-11-lost-chance-modifiers" aria-label="Permalink to &quot;**Table 10.11: Lost Chance Modifiers**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Condition</th><th>Modifier</th></tr></thead><tbody><tr><td>Navigator in group</td><td>−30%</td></tr><tr><td>Landmark sighted</td><td>−20%</td></tr><tr><td>Raining</td><td>+10%</td></tr><tr><td>Fog or mist</td><td>+30%</td></tr><tr><td>Overcast sky</td><td>+30%</td></tr><tr><td>Poor trail</td><td>+10%</td></tr><tr><td>No landmarks</td><td>+50%</td></tr><tr><td>Darkness</td><td>+70%</td></tr><tr><td>Local guide</td><td>Variable</td></tr><tr><td>Directions, map, tools</td><td>Variable</td></tr></tbody></table><hr><h2 id="swimming" tabindex="-1"><strong>Swimming</strong> <a class="header-anchor" href="#swimming" aria-label="Permalink to &quot;**Swimming**&quot;">​</a></h2><p>A character can swim at a number of meters per round equal to half their MV × 10. A burst of speed allows their full MV × 10 meters in a single round, requiring a Strength check against half the character&#39;s Strength score (exceptional Strength counts as 9). Metal armor causes immediate sinking; armored characters can walk along the bottom at one-third MV × 10 meters per round.</p><p><strong>Endurance.</strong> A character can swim at half speed for a number of hours equal to their Constitution score without difficulty. Each additional hour requires a Constitution check. On failure, the character must tread water for 30 minutes before continuing. Each additional hour spent swimming reduces Constitution by 1 temporarily and applies a cumulative −1 to attack rolls. A character whose Constitution drops to 0 while swimming drowns.</p><p><strong>Rough water.</strong> Choppy water or swimming against the tide requires a Constitution check every hour. Rough water or swimming against a heavy tide requires a check every 30 minutes. Stormy water requires a check every round.</p><p><strong>Hustle swimming.</strong> A character swimming at full MV × 10 meters per round must check Constitution every hour and loses 1 Strength and 1 Constitution per hour, plus a cumulative −2 to attack rolls. Swimming at double that rate requires checks every turn; penalties accrue every turn. Drowning occurs if either Strength or Constitution reaches 0.</p><p><strong>Recovery.</strong> Each day of rest restores 1d6 ability points (1d3 each for Strength and Constitution if the swimming was at hustle or faster) and 2d6 points of attack penalty.</p><h3 id="holding-breath" tabindex="-1"><strong>Holding Breath</strong> <a class="header-anchor" href="#holding-breath" aria-label="Permalink to &quot;**Holding Breath**&quot;">​</a></h3><p>With a gulp of air, a character holds their breath for rounds equal to one-third their Constitution (round up). Exertion — moving more than half MV, fighting, swimming in rough water, or wearing metal armor — halves this. Without preparation, halve the time again. A character can hold their breath for at least 1 round regardless of circumstances.</p><p>Holding breath beyond this limit requires a Constitution check each round, with a cumulative −2 penalty per check. Failure means the character must breathe.</p><p><strong>Diving.</strong> A swimmer descends up to 6 meters per round. A running start or elevated jump adds depth — up to 6 additional meters (1.5 meters per 3 meters of height). To dive safely from height, the water must be at least 1 meter deep per 3 meters of the dive&#39;s height.</p><p><strong>Surfacing.</strong> Characters rise at up to 6 meters per round. Unconscious or dead characters float up at 1.5 meters per round.</p><h3 id="vision-underwater" tabindex="-1"><strong>Vision Underwater</strong> <a class="header-anchor" href="#vision-underwater" aria-label="Permalink to &quot;**Vision Underwater**&quot;">​</a></h3><p>In bright sunlight, vision extends to 45 meters in fresh water and 30 meters in salt water. For every 3 meters below the surface, vision reduces by 3 meters until it becomes darkness. On overcast days, underwater vision is halved. On moonless nights, vision is zero. Artificial light (including magical) illuminates half its normal radius underwater.</p><hr><h2 id="climbing" tabindex="-1"><strong>Climbing</strong> <a class="header-anchor" href="#climbing" aria-label="Permalink to &quot;**Climbing**&quot;">​</a></h2><p>Climbing requires equipment for most characters — ropes and pitons. Only Thieves can climb without equipment; they use their Climb Walls thief skill instead of the standard check.</p><p>A climb check is made before beginning any ascent exceeding 3 meters. Base success chance is 40%, modified by conditions. A successful check requires no further rolls unless conditions worsen. A failed check means no viable path was found; the character cannot try again unless conditions improve or they find a suitable location at least 1 kilometer away.</p><p>Characters cannot use two-handed items while climbing unless they find secure footing. Taking damage while climbing requires an immediate climb check to maintain grip. A roped character who fails spends a round regaining their hold. An un-roped character falls.</p><p><strong>Climb speed.</strong> All characters move MV × 0.3 meters per round (up, down, sideways, or diagonally) when climbing, multiplied by the surface modifier. Thieves climb at double speed; their modifiers are listed in brackets.</p><h3 id="table-10-12-climbing-modifiers" tabindex="-1"><strong>Table 10.12: Climbing Modifiers</strong> <a class="header-anchor" href="#table-10-12-climbing-modifiers" aria-label="Permalink to &quot;**Table 10.12: Climbing Modifiers**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Condition</th><th>Modifier</th></tr></thead><tbody><tr><td>Prominent handholds (branches, ledges)</td><td>+40%</td></tr><tr><td>Rope anchored at top</td><td>+55%</td></tr><tr><td>Surface slopes inward</td><td>+25%</td></tr><tr><td>Slightly slippery (wet or crumbling)</td><td>−25%</td></tr><tr><td>Slippery (icy or slimy)</td><td>−45%</td></tr><tr><td>At 50% HP or less</td><td>−30%</td></tr><tr><td>Encumbrance penalty</td><td>−10% per step below base speed</td></tr><tr><td>Banded or splint armor</td><td>−35%</td></tr><tr><td>Plate armor variants</td><td>−50%</td></tr><tr><td>Chain or scale armor</td><td>−25%</td></tr><tr><td>Studded or padded</td><td>−15%</td></tr><tr><td>Duardeen or Duergar</td><td>−10%</td></tr><tr><td>Halfling (Val&#39;arian)</td><td>−20%</td></tr></tbody></table><h3 id="table-10-13-climbing-speed-modifiers" tabindex="-1"><strong>Table 10.13: Climbing Speed Modifiers</strong> <a class="header-anchor" href="#table-10-13-climbing-speed-modifiers" aria-label="Permalink to &quot;**Table 10.13: Climbing Speed Modifiers**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Surface</th><th>Dry</th><th>Slightly Slippery</th><th>Slippery</th></tr></thead><tbody><tr><td>Very smooth*</td><td>×½</td><td>—</td><td>—</td></tr><tr><td>Smooth, cracked*</td><td>×½ [×1]</td><td>×¼</td><td>—</td></tr><tr><td>Rough*</td><td>×1 [×2]</td><td>×½</td><td>—</td></tr><tr><td>Rough with ledges</td><td>×1 [×2]</td><td>×½ [×1]</td><td>×¼</td></tr><tr><td>Ice wall</td><td>—</td><td>—</td><td>—</td></tr><tr><td>Tree</td><td>×4 [×8]</td><td>×3 [×6]</td><td>×2 [×4]</td></tr><tr><td>Sloping wall</td><td>×3 [×6]</td><td>×2 [×4]</td><td>×1 [×2]</td></tr><tr><td>Rope against wall</td><td>×2 [×4]</td><td>×1 [×2]</td><td>×½ [×1]</td></tr></tbody></table><p>* <em>Non-Thieves require climbing equipment for these surfaces. Very smooth, slippery surfaces cannot be climbed with mundane tools.</em></p><p><em>Thief speeds in brackets.</em></p><h3 id="climbing-tools" tabindex="-1"><strong>Climbing Tools</strong> <a class="header-anchor" href="#climbing-tools" aria-label="Permalink to &quot;**Climbing Tools**&quot;">​</a></h3><p>Pitons, ropes, and ice axes prevent falling rather than increasing speed. A character can only fall as far as their rope — or twice the distance to the last placed piton (pitons have a 15% chance of coming loose in a fall). Falling characters still take 1d6 per 3 meters from the rope catching them.</p><p><strong>Roped groups.</strong> When one character falls, those directly roped to them make a climb check (−2 per additional falling character). Success stops the fall; failure means that character also falls, and the check propagates down the line.</p><p><strong>Rappelling.</strong> A character with an anchored rope can descend at MV × 3 meters per round, with a +50% bonus to their climb check if someone holds the rope at the bottom, or +30% for free rappel.</p><hr><h2 id="vision-and-light" tabindex="-1"><strong>Vision and Light</strong> <a class="header-anchor" href="#vision-and-light" aria-label="Permalink to &quot;**Vision and Light**&quot;">​</a></h2><p>Under clear conditions, the horizon is visible at roughly 20 kilometers. Tall mountains can be seen at 100 kilometers. Specific visibility conditions:</p><h3 id="table-10-14-visibility-ranges-in-meters" tabindex="-1"><strong>Table 10.14: Visibility Ranges (in Meters)</strong> <a class="header-anchor" href="#table-10-14-visibility-ranges-in-meters" aria-label="Permalink to &quot;**Table 10.14: Visibility Ranges (in Meters)**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Condition</th><th>Movement Seen</th><th>Spotted</th><th>Type Identified</th><th>Detail Identified</th></tr></thead><tbody><tr><td>Clear sky</td><td>1,500 m</td><td>1,000 m</td><td>500 m</td><td>100 m</td></tr><tr><td>Twilight</td><td>500 m</td><td>300 m</td><td>150 m</td><td>30 m</td></tr><tr><td>Mist, light rain</td><td>1,000 m</td><td>500 m</td><td>250 m</td><td>30 m</td></tr><tr><td>Light fog or snow</td><td>500 m</td><td>200 m</td><td>100 m</td><td>30 m</td></tr><tr><td>Night, full moon</td><td>100 m</td><td>50 m</td><td>30 m</td><td>10 m</td></tr><tr><td>Night, no moon</td><td>50 m</td><td>20 m</td><td>10 m</td><td>5 m</td></tr><tr><td>Dense fog or blizzard</td><td>10 m</td><td>10 m</td><td>5 m</td><td>5 m</td></tr></tbody></table><p><strong>Movement Seen:</strong> the distance at which motion is detectable. <strong>Spotted:</strong> the maximum distance at which any object can be seen. <strong>Type:</strong> general category (ancestry, weapons, clothing). <strong>Detail:</strong> specific individuals and features.</p><p>Small creatures reduce all categories by one step per size below medium. Large creatures double the Movement, Spotted, and Type ranges per size category above medium.</p><h3 id="table-10-15-light-sources" tabindex="-1"><strong>Table 10.15: Light Sources</strong> <a class="header-anchor" href="#table-10-15-light-sources" aria-label="Permalink to &quot;**Table 10.15: Light Sources**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source</th><th>Radius</th><th>Duration per Fuel Unit</th></tr></thead><tbody><tr><td>Candle, tallow</td><td>1.5 m</td><td>10 min/cm</td></tr><tr><td>Candle, wax</td><td>2 m</td><td>20 min/cm</td></tr><tr><td>Torch</td><td>4.5 m</td><td>30 minutes</td></tr><tr><td>Light (spell)</td><td>6 m</td><td>Variable</td></tr><tr><td>Hooded lantern</td><td>9 m</td><td>6 hours/500 ml</td></tr><tr><td>Campfire</td><td>10 m</td><td>1 hour/armload</td></tr><tr><td>Bonfire</td><td>15 m</td><td>30 min/armload</td></tr><tr><td>Continual light</td><td>20 m</td><td>Indefinite</td></tr><tr><td>Bull&#39;s-eye lantern*</td><td>20 m</td><td>6 hours/500 ml</td></tr><tr><td>Beacon lantern*</td><td>70 m</td><td>2 hours/500 ml</td></tr></tbody></table><p>* <em>Cone-shaped beam. Bull&#39;s-eye: 6 meters wide at far end. Beacon: 30 meters wide at the far end.</em></p><h3 id="darkness" tabindex="-1"><strong>Darkness</strong> <a class="header-anchor" href="#darkness" aria-label="Permalink to &quot;**Darkness**&quot;">​</a></h3><p>In total darkness, movement drops to one-third normal MV. Characters without adequate light suffer −4 to attack rolls and Reflex saves, and their AC is reduced by 4 (maximum unmodified AC 10 regardless of armor).</p><h3 id="infravision-and-darkvision" tabindex="-1"><strong>Infravision and Darkvision</strong> <a class="header-anchor" href="#infravision-and-darkvision" aria-label="Permalink to &quot;**Infravision and Darkvision**&quot;">​</a></h3><p><strong>Infravision</strong> allows creatures to see heat signatures in non-magical darkness — warm-blooded creatures and heat sources appear visible at up to 20 meters. Infravision images are in greyscale; colors are indistinguishable. Cold objects are not visible.</p><p><strong>Darkvision</strong> (Duergar only) allows complete vision in darkness as clearly as daylight — full color, cold objects included, no range limitation within normal sight distance. See Chapter 1 and Chapter 2 for ancestral rules.</p><hr><h2 id="hearing" tabindex="-1"><strong>Hearing</strong> <a class="header-anchor" href="#hearing" aria-label="Permalink to &quot;**Hearing**&quot;">​</a></h2><p>Clear, distinctive sounds require no check. Difficult hearing — discerning a single voice among many, hearing through walls, pinpointing direction — requires a check.</p><h3 id="table-10-16-hearing-chance-by-ancestry" tabindex="-1"><strong>Table 10.16: Hearing Chance by Ancestry</strong> <a class="header-anchor" href="#table-10-16-hearing-chance-by-ancestry" aria-label="Permalink to &quot;**Table 10.16: Hearing Chance by Ancestry**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Ancestry</th><th>d100</th><th>d20 (equal or under)</th></tr></thead><tbody><tr><td>Human</td><td>15%</td><td>3</td></tr><tr><td>Húldar</td><td>20%</td><td>4</td></tr><tr><td>Aelár</td><td>20%</td><td>4</td></tr><tr><td>Duardeen</td><td>15%</td><td>3</td></tr><tr><td>Duergar</td><td>25%</td><td>5</td></tr><tr><td>Badaki</td><td>15%</td><td>3</td></tr><tr><td>Ûrgon</td><td>20%</td><td>4</td></tr><tr><td>Val&#39;arian</td><td>25%</td><td>5</td></tr><tr><td>Vartran</td><td>15%</td><td>3</td></tr></tbody></table><p>Optimal conditions require: helmet removed, standing still, one round of concentration. On failure, the character cannot discern the target sound until conditions change. On success, they may make further checks to determine direction, number of sources, and other details.</p><hr><h2 id="using-mirrors" tabindex="-1"><strong>Using Mirrors</strong> <a class="header-anchor" href="#using-mirrors" aria-label="Permalink to &quot;**Using Mirrors**&quot;">​</a></h2><p>Actions taken using a mirror or reflective surface impose −2 to all checks, proficiency checks, and attack rolls. Defending against a target viewed only in reflection forfeits the Dexterity AC bonus.</p><hr><h2 id="doors" tabindex="-1"><strong>Doors</strong> <a class="header-anchor" href="#doors" aria-label="Permalink to &quot;**Doors**&quot;">​</a></h2><p>Ordinary doors require no check. Stuck, damaged, or heavily barred doors require a Force Doors roll from Table 1.1 (Strength). Each failed attempt reduces the chance by 1. Two characters can combine half their Force Doors ratings rounded up; with a running start, they add full ratings together.</p><p>A forced door is destroyed or knocked off its hinges. Forcing doors makes considerable noise — the GM should check for a wandering encounter immediately if this occurs in a dungeon.</p><h3 id="secret-and-concealed-doors" tabindex="-1"><strong>Secret and Concealed Doors</strong> <a class="header-anchor" href="#secret-and-concealed-doors" aria-label="Permalink to &quot;**Secret and Concealed Doors**&quot;">​</a></h3><p>Secret doors are disguised as normal walls or objects. Concealed doors are simply hidden. Searching a 6-meter section of wall takes 10 minutes (1 turn) for an average character.</p><p>Húldar and Aelár notice secret or concealed doors when passing within 3 meters without actively searching (1 on 1d6). When searching actively: secret doors 1–2 on 1d6, concealed doors 1–3 on 1d6.</p><p>If found, the opening mechanism is usually apparent. In cases where it is not, a character who knows the door exists gains +1 to find the mechanism. Secret doors can be forced at half the normal Force Doors rating.</p><hr><h2 id="invisibility" tabindex="-1"><strong>Invisibility</strong> <a class="header-anchor" href="#invisibility" aria-label="Permalink to &quot;**Invisibility**&quot;">​</a></h2><p>An invisible creature is undetectable by normal sight or infravision. They impose −4 to attack rolls against them. Complex actions while invisible (picking a lock, fine manipulation) suffer −3 (or −15%).</p><p>Invisibility does not mask sound, scent, or heat signatures from infravision-capable observers. Objects like flour or mud can reveal an invisible creature&#39;s location and shape.</p><p>If an invisible creature gives away their position — by smell, sound, or touch — alert characters make a Will save. On success, the character knows an invisible presence is nearby and may attack the general area at −4. On failure, they remain unaware until a new triggering event occurs.</p><p>Light is not hidden by invisibility — a light source carried by an invisible creature is visible, even if the carrier is not.</p><hr><h2 id="damage-death-and-healing" tabindex="-1"><strong>Damage, Death, and Healing</strong> <a class="header-anchor" href="#damage-death-and-healing" aria-label="Permalink to &quot;**Damage, Death, and Healing**&quot;">​</a></h2><h3 id="hit-points" tabindex="-1"><strong>Hit Points</strong> <a class="header-anchor" href="#hit-points" aria-label="Permalink to &quot;**Hit Points**&quot;">​</a></h3><p>Hit points are an abstraction of a character&#39;s ability to survive. A character taking 8 points of damage loses 8 hit points, whether struck in the head or arm. Damage bonuses and penalties apply after the dice are rolled. Damage cannot be reduced below 1 point. Damage multipliers apply to dice only — modifiers are added after all dice are rolled, and never multiplied.</p><h3 id="special-damage-conditions" tabindex="-1"><strong>Special Damage Conditions</strong> <a class="header-anchor" href="#special-damage-conditions" aria-label="Permalink to &quot;**Special Damage Conditions**&quot;">​</a></h3><p><strong>Blindness.</strong> −4 to attack rolls and Reflex saves. AC reduced by 4. The character loses Dexterity-based attack bonuses, though penalties remain.</p><p><strong>Deafness.</strong> −1 to surprise rolls, −1 to initiative. Spellcasters have a 20% chance of failure when casting spells with verbal components.</p><p><strong>Falling.</strong> 1d6 damage per 3 meters fallen, maximum 20d6. The GM may reduce damage based on the landing surface — soft ground, water, or vegetation.</p><p><strong>Energy Drain.</strong> A character hit by an energy-draining attack suffers normal damage and loses one or more experience levels. For each level lost, roll the class hit die plus Constitution modifier and subtract from maximum HP. Drained experience is dropped to halfway between the new level and the next. All powers from the lost level disappear immediately; spellcasters forget spells above their new casting capacity.</p><p>A character drained to 0 level becomes a 0-level character, unable to use former class abilities or gain levels. A second energy drain at 0 level is instantly fatal. Raise Dead, Resurrection, or Wish can restore a 0-level character to 1st level.</p><p>A character drained below 0 levels rises in 2d4 days as an undead minion of whatever slew them, retaining half their former levels, under the GM&#39;s control. The minion is freed when its master is destroyed and can accumulate HD through further energy drain.</p><p><strong>Insanity (Permanent).</strong> Affected creatures function normally until encountering a stressful situation (combat, surprise, high-stakes tasks, unfamiliar social encounters). A Wisdom check is required; failure causes the insanity to manifest for 2+1d4 turns. Roll 1d6 for behavior:</p><table tabindex="0"><thead><tr><th>1d6</th><th>Behavior</th></tr></thead><tbody><tr><td>1</td><td>Drops prone and babbles uncontrollably</td></tr><tr><td>2</td><td>Violently attacks the perceived cause, then collapses, babbling</td></tr><tr><td>3</td><td>Flees as fast as possible; collapses if no escape is available</td></tr><tr><td>4</td><td>Acts normally, but the next manifestation&#39;s duration is doubled</td></tr><tr><td>5</td><td>Randomly attacks the nearest creature or object</td></tr><tr><td>6</td><td>Uncontrollable screaming and cursing at the perceived cause</td></tr></tbody></table><p>While insanity manifests, the creature can still defend itself and cast spells, but cannot act rationally or employ tactics. It gains a Will save against enchantment effects that ordinarily do not allow one, and +4 to Will saves against other enchantments. A trusted ally&#39;s sustained effort (one round at a time) provides +1 per round to the creature&#39;s Wisdom check to suppress the episode.</p><p><strong>Insanity (Temporary).</strong> Effects lasting one hour or less are treated as a confusion spell.</p><p><strong>Paralysis.</strong> The character is completely immobile, drops held items, and loses all Dexterity AC bonuses. They cannot move, fly, swim, or speak, but can breathe, think, see, and hear. Abilities activated by thought still function. All melee attacks against a paralyzed character hit automatically.</p><p><strong>Stunned.</strong> The character cannot take coherent actions, use abilities, flee, or engage in combat. They may drop held items or fall prone at the GM&#39;s discretion. Opponents gain +4 to attack rolls against a stunned character.</p><h3 id="poison" tabindex="-1"><strong>Poison</strong> <a class="header-anchor" href="#poison" aria-label="Permalink to &quot;**Poison**&quot;">​</a></h3><p>Poison is classified by delivery method (injected, ingested, contact) and onset time. When affected, a Fortitude save is made.</p><h3 id="table-10-17-poison-classes" tabindex="-1"><strong>Table 10.17: Poison Classes</strong> <a class="header-anchor" href="#table-10-17-poison-classes" aria-label="Permalink to &quot;**Table 10.17: Poison Classes**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Class</th><th>Method</th><th>Onset</th><th>Damage (Fail/Save)</th></tr></thead><tbody><tr><td>A</td><td>Injected</td><td>1d3×10 min</td><td>15 / 0</td></tr><tr><td>B</td><td>Injected</td><td>2d6 min</td><td>20 / 1</td></tr><tr><td>C</td><td>Injected</td><td>1d4+1 min</td><td>25 / 2</td></tr><tr><td>D</td><td>Injected</td><td>1d2 min</td><td>30 / 2</td></tr><tr><td>E</td><td>Injected</td><td>Immediate</td><td>Death / 20</td></tr><tr><td>F</td><td>Injected</td><td>Immediate</td><td>Death / 0</td></tr><tr><td>G</td><td>Ingested</td><td>2d6 hours</td><td>20 / 10</td></tr><tr><td>H</td><td>Ingested</td><td>1d4 min</td><td>20 / 10</td></tr><tr><td>I</td><td>Ingested</td><td>2d6 min</td><td>30 / 15</td></tr><tr><td>J</td><td>Ingested</td><td>1d4 min</td><td>Death / 20</td></tr><tr><td>K</td><td>Contact</td><td>2d4 min</td><td>5 / 0</td></tr><tr><td>L</td><td>Contact</td><td>2d4 min</td><td>10 / 0</td></tr><tr><td>M</td><td>Contact</td><td>1d4 min</td><td>20 / 5</td></tr><tr><td>N</td><td>Contact</td><td>1 min</td><td>Death / 25</td></tr><tr><td>O</td><td>Injected</td><td>2d12 min</td><td>Paralytic</td></tr><tr><td>P</td><td>Injected</td><td>1d3 hours</td><td>Debilitative</td></tr></tbody></table><p><strong>Paralytic:</strong> Paralyzed for 2d6 hours. <strong>Debilitative:</strong> All ability scores halved, movement halved, cannot heal by any means until poison is neutralized or exits the body after 1d3 days.</p><p>If an ingested poison is injected (or vice versa) and the save fails, apply normal effects. If the save succeeds in this misapplication, no effect occurs.</p><p>Spells and abilities that heal hit points do not neutralize poison. Spells that neutralize poison do not restore hit points lost to it.</p><h3 id="death" tabindex="-1"><strong>Death</strong> <a class="header-anchor" href="#death" aria-label="Permalink to &quot;**Death**&quot;">​</a></h3><p>A character reaching 0 hit points dies immediately and is incapable of further action without specialized magic.</p><p><strong>Death from poison.</strong> Poison remains active in the bloodstream for 2d6 hours after death. A raised character must make a Fortitude save against the poison still present in their body.</p><p><strong>Massive damage.</strong> A character who takes 50 or more points of damage from a single attack or source must immediately make a Fortitude save or drop to 0 hit points and die from shock. This applies only to damage from a single source.</p><h3 id="raising-the-dead" tabindex="-1"><strong>Raising the Dead</strong> <a class="header-anchor" href="#raising-the-dead" aria-label="Permalink to &quot;**Raising the Dead**&quot;">​</a></h3><p>Each time a character is restored to life — by Raise Dead, Resurrection, or similar magic — they make a Constitution resurrection check (Table 1.2). Failure means the character does not survive the process and cannot be raised again. A successful restoration costs 1 point of Constitution permanently. A character whose Constitution reaches 0 cannot be raised. The character&#39;s starting Constitution score represents the maximum number of times it can ever be raised.</p><h3 id="healing" tabindex="-1"><strong>Healing</strong> <a class="header-anchor" href="#healing" aria-label="Permalink to &quot;**Healing**&quot;">​</a></h3><p><strong>Natural healing.</strong> 1 hit point per day of rest (activities no more strenuous than walking or riding). Physical labor, combat, or running prevents healing for the rest of that day. Complete bed rest (no strenuous activity for a full day) restores 3 hit points. After a full week of complete bed rest, add the character&#39;s Constitution HP modifier to the total.</p><p><strong>Magical healing.</strong> Cure wound spells and healing potions restore HP instantly. Excess healing beyond the maximum is wasted. Magical healing is neither good nor evil and carries no alignment implications for the caster.</p><h3 id="table-10-18-constitution-and-recovery-time" tabindex="-1"><strong>Table 10.18: Constitution and Recovery Time</strong> <a class="header-anchor" href="#table-10-18-constitution-and-recovery-time" aria-label="Permalink to &quot;**Table 10.18: Constitution and Recovery Time**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Constitution</th><th>Effect on Recovery</th></tr></thead><tbody><tr><td>3–4</td><td>Double recovery time</td></tr><tr><td>5–6</td><td>One-and-a-half times recovery time</td></tr><tr><td>16–17</td><td>Reduce recovery time by one-third</td></tr><tr><td>18+</td><td>Reduce recovery time by half</td></tr></tbody></table><h3 id="disease" tabindex="-1"><strong>Disease</strong> <a class="header-anchor" href="#disease" aria-label="Permalink to &quot;**Disease**&quot;">​</a></h3><p><strong>Mundane diseases</strong> spread like poisons (by contact, injection, or ingestion) and are treated by the Healing skill and Herbalism — see Chapter 7. A successful Healing check reduces variable damage and duration to a minimum; further magical treatment is not required.</p><p><strong>Magical diseases</strong> can be diagnosed by a healer with Herbalism training, but require magical treatment to cure.</p>',183)])])}const g=e(n,[["render",o]]);export{u as __pageData,g as default};
